INSERT INTO invitro.mv_assay_annotation (aeid,assay_component_endpoint_name,assay_component_endpoint_desc,assay_function_type,normalized_data_type,burst_assay,key_positive_control,signal_direction,intended_target_type,intended_target_type_sub,intended_target_family,intended_target_family_sub,cell_viability_assay,acid,assay_component_name,assay_component_desc,assay_component_target_desc,parameter_readout_type,assay_design_type,assay_design_type_sub,biological_process_target,detection_technology_type,detection_technology_type_sub,detection_technology,key_assay_reagent_type,key_assay_reagent,technological_target_type,technological_target_type_sub,aid,assay_name,assay_desc,timepoint_hr,organism_id,organism,ncbi_taxon_id,taxon_name,common_name,lineage,tissue,cell_format,cell_free_component_source,cell_short_name,cell_growth_mode,assay_footprint,assay_format_type,assay_format_type_sub,content_readout_type,dilution_solvent,dilution_solvent_percent_max,asid,assay_source_name,assay_source_long_name,assay_source_desc,clowder_uid,gene,assay_list,citations,assay_reagent,mc2_methods,mc3_methods,mc4_methods,mc5_methods,mc6_methods,sc1_methods,sc2_methods,export_date,data_version) VALUES
	 (111,'ATG_TCF_b_cat_CIS','Data from the assay component ATG_TCF_b_cat_CIS was analyzed into 1 assay endpoint. This assay endpoint, ATG_TCF_b_cat_CIS, was analyzed with bidirectional fitting relative to DMSO as the negative control and baseline of activity. Using a type of inducible reporter, measures of mRNA for gain or loss-of-signal activity can be used to understand the reporter gene at the transcription factor-level as they relate to the gene TCF7 and TCF7L2 and LEF1 and TCF7L1. Furthermore, this assay endpoint can be referred to as a primary readout, because this assay has produced multiple assay endpoints where this one serves a reporter gene function. To generalize the intended target to other relatable targets, this assay endpoint is annotated to the dna binding intended target family, where the subfamily is HMG box protein.','reporter gene','log2_fold_induction',0,'NA','bidirectional','protein','transcription factor','dna binding','HMG box protein',0,80,'ATG_TCF_b_cat_CIS','ATG_TCF_b_cat_CIS is one of 52 assay component(s) measured or calculated from the ATG_CIS assay. It is designed to make measurements of mRNA induction, a form of inducible reporter, as detected with fluorescence intensity signals by Reverse transcription polymerase chain reaction (RT-PCR) and Capillary electrophoresis technology.','Changes to fluorescence intensity signals are indicative of inducible changes in transcription factor activity. This is quantified by the level of mRNA reporter sequence unique to the cis-acting reporter gene TCF/b-cat, which is responsive to the endogenous human transcription factor 7 (T-cell specific, HMG-box) and transcription factor 7-like 2 (T-cell specific, HMG-box) and lymphoid enhancer-binding factor 1 and transcription factor 7-like 1 (T-cell specific, HMG-box) [GeneSymbol:TCF7 & TCF7L2 & LEF1 & TCF7L1 | GeneID:6932 & 6934 & 51176 & 83439 | Uniprot_SwissProt_Accession:P36402 & Q9NQB0 & Q9UJU2 & Q9HCS4].','single','inducible reporter','mRNA induction','regulation of transcription factor activity','Fluorescence','Fluorescence intensity','RT-PCR and Capillary electrophoresis','inducer','TCF/b-cat RTU','rna','mRNA',5,'ATG_CIS','ATG_CIS is a cell-based, multiplexed-readout assay that uses HepG2, a human liver cell line, with measurements taken at 24 hours after chemical dosing in a 24-well plate.',24.0,9606,'human',9606,'Homo sapiens','human','Eukaryota; Metazoa; Chordata; Craniata; Vertebrata; Euteleostomi; Mammalia; Eutheria; Euarchontoglires; Primates; Haplorrhini; Catarrhini; Hominidae; Homo','liver','cell line','NA','HepG2','adherent','microplate: 24-well plate','cell-based','cell-based format','multiplexed','DMSO',1.0,3,'ATG','Attagene','Attagene Inc. is a Contract Research Organization (CRO) offering a unique screening service using its proprietary multiplexed pathway profiling platform, the FACTORIAL.','66df2d48e4b0a7c65d2ec1cb ','[{"gene_id": 311, "gene_name": "transcription factor 7 (T-cell specific, HMG-box)", "description": null, "gene_symbol": "TCF7", "organism_id": 1, "track_status": "live", "entrez_gene_id": 6932, "official_symbol": "TCF7", "official_full_name": "transcription factor 7 (T-cell specific, HMG-box)", "uniprot_accession_number": "P36402"}, {"gene_id": 312, "gene_name": "transcription factor 7-like 2 (T-cell specific, HMG-box)", "description": null, "gene_symbol": "TCF7L2", "organism_id": 1, "track_status": "live", "entrez_gene_id": 6934, "official_symbol": "TCF7L2", "official_full_name": "transcription factor 7-like 2 (T-cell specific, HMG-box)", "uniprot_accession_number": "Q9NQB0"}, {"gene_id": 426, "gene_name": "lymphoid enhancer-binding factor 1", "description": null, "gene_symbol": "LEF1", "organism_id": 1, "track_status": "live", "entrez_gene_id": 51176, "official_symbol": "LEF1", "official_full_name": "lymphoid enhancer-binding factor 1", "uniprot_accession_number": "Q9UJU2"}, {"gene_id": 438, "gene_name": "transcription factor 7-like 1 (T-cell specific, HMG-box)", "description": null, "gene_symbol": "TCF7L1", "organism_id": 1, "track_status": "live", "entrez_gene_id": 83439, "official_symbol": "TCF7L1", "official_full_name": "transcription factor 7-like 1 (T-cell specific, HMG-box)", "uniprot_accession_number": "Q9HCS4"}]',NULL,'[{"doi": "10.1038/nmeth.1186", "url": "http://www.ncbi.nlm.nih.gov/pubmed/18297081", "pmid": 18297081, "title": "Homogeneous reporter system enables quantitative functional assessment of multiple transcription factors", "author": "Romanov S, Medvedev A, Gambarian M, Poltoratskaya N, Moeser M, Medvedeva L, Gambarian M, Diatchenko L, Makarov S", "citation": "Romanov S, Medvedev A, Gambarian M, Poltoratskaya N, Moeser M, Medvedeva L, Gambarian M, Diatchenko L, Makarov S. Homogeneous reporter system enables quantitative functional assessment of multiple transcription factors. Nat Methods. 2008 Mar;5(3):253-60. doi: 10.1038/nmeth.1186. Epub 2008 Feb 24. PubMed PMID: 18297081.", "other_id": "0", "citation_id": 211, "other_source": ""}, {"doi": "10.1021/tx900325g", "url": "http://www.ncbi.nlm.nih.gov/pubmed/20143881", "pmid": 20143881, "title": "Impact of environmental chemicals on key transcription regulators and correlation to toxicity end points within EPA''s ToxCast program", "author": "Martin MT, Dix DJ, Judson RS, Kavlock RJ, Reif DM, Richard AM, Rotroff DM, Romanov S, Medvedev A, Poltoratskaya N, Gambarian M, Moeser M, Makarov SS, Houck KA", "citation": "Martin MT, Dix DJ, Judson RS, Kavlock RJ, Reif DM, Richard AM, Rotroff DM, Romanov S, Medvedev A, Poltoratskaya N, Gambarian M, Moeser M, Makarov SS, Houck KA. Impact of environmental chemicals on key transcription regulators and correlation to toxicity end points within EPA''s ToxCast program. Chem Res Toxicol. 2010 Mar 15;23(3):578-90. doi: 10.1021/tx900325g. PubMed PMID: 20143881.", "other_id": "0", "citation_id": 212, "other_source": ""}, {"doi": "10.1126/sciadv.aar4666", "url": "https://pubmed.ncbi.nlm.nih.gov/30263952/", "pmid": 30263952, "title": "Evaluating biological activity of compounds by transcription factor activity profiling", "author": "Medvedev A, Moeser M, Medvedeva L, Martsen E, Granick A, Raines L, Zeng M, Makarov S, Houck KA, Makarov SS", "citation": "Medvedev A, Moeser M, Medvedeva L, Martsen E, Granick A, Raines L, Zeng M, Makarov S Jr, Houck KA, Makarov SS. Evaluating biological activity of compounds by transcription factor activity profiling. Sci Adv. 2018 Sep 26;4(9):eaar4666. doi: 10.1126/sciadv.aar4666. PMID: 30263952; PMCID: PMC6157966.", "other_id": "0", "citation_id": 236, "other_source": ""}]','[{"culture_or_assay": "culture", "reagent_name_value": "Cis MRTU library", "reagent_name_value_type": "inducer"}, {"culture_or_assay": "culture", "reagent_name_value": "FuGene 6 reagent", "reagent_name_value_type": "potentiator"}, {"culture_or_assay": "assay", "reagent_name_value": "TriZol", "reagent_name_value_type": "extractor"}, {"culture_or_assay": "assay", "reagent_name_value": "DNAse I", "reagent_name_value_type": "potentiator"}, {"culture_or_assay": "assay", "reagent_name_value": "oligo(dT) primers", "reagent_name_value_type": "cofactor"}, {"culture_or_assay": "assay", "reagent_name_value": "Mo-MLV reverse transcriptase", "reagent_name_value_type": "potentiator"}, {"culture_or_assay": "assay", "reagent_name_value": "Taq polymerase", "reagent_name_value_type": "potentiator"}, {"culture_or_assay": "assay", "reagent_name_value": "6-carboxyfluorescein 5''-labeled reporter primers", "reagent_name_value_type": "coupled substrate"}, {"culture_or_assay": "assay", "reagent_name_value": "HpaI", "reagent_name_value_type": "potentiator"}, {"culture_or_assay": "assay", "reagent_name_value": "37", "reagent_name_value_type": "media_temp_celsius_min"}, {"culture_or_assay": "assay", "reagent_name_value": "95", "reagent_name_value_type": "media_temp_celsius_max"}, {"culture_or_assay": "assay", "reagent_name_value": "24", "reagent_name_value_type": "media_time_hr"}]','[{"desc": "Exclude wells with negative corrected response values (cval) and downgrading their well quality (wllq); if cval < 0, wllq = 0.", "mc2_mthd": "rmneg", "exec_ordr": 1, "mc2_mthd_id": 3}, {"desc": "Exclude wells with corrected response values (cval) equal to zero and downgrading their well quality (wllq); if cval = 0, wllq = 0.", "mc2_mthd": "rmzero", "exec_ordr": 2, "mc2_mthd_id": 4}, {"desc": "Transform the corrected response value (cval) to log-scale (base 2).", "mc2_mthd": "log2", "exec_ordr": 3, "mc2_mthd_id": 2}]','[{"desc": "Set the corrected response value (cval) as the normalized response value (resp); cval = resp. No additional mc3 methods needed for endpoint-specific normalization.", "mc3_mthd": "none", "mc3_mthd_id": 1}]','[{"desc": "Calculate the baseline median absolute value (bmad) as the median absolute deviation of normalized response values (rep) for test compound wells (wllt = t) with concentration index (cndx) equal to 1 or 2. Calculate one standard deviation of the normalized response for test compound wells (wllt = t) with a concentration index (cndx) of 1 or 2; onesd = sqrt(sum((resp - mean resp)^2)/sample size - 1). Onesd is used to establish BMR and therefore required for tcplfit2 processing.", "mc4_mthd": "bmad.aeid.lowconc.twells", "mc4_mthd_id": 1}]','[{"desc": "Add a cutoff value of log2(1.2). Typically for fold change data.", "mc5_mthd": "log2_1.2", "mc5_mthd_id": 3}, {"desc": "Add a cutoff value of 5 multiplied the baseline median absolute deviation (bmad). By default, bmad is calculated using test compound wells (wllt = t) for the endpoint.", "mc5_mthd": "bmad5", "mc5_mthd_id": 5}]','[{"desc": "Flag series where no median response values are greater than baseline as defined by 3 times the baseline median absolute deviation (bmad); nmed_gtbl_pos and nmed_gtbl_neg both = 0, where nmed_gtbl_pos/_neg is the number of medians greater than 3*bmad/less than -3*bmad.", "mc6_mthd": "no.med.gt.3bmad", "mc6_mthd_id": 20}, {"desc": "Flag series with an active hit call (hitc >= 0.9) if AC50 (concentration at 50 percent maximal response) is less than the lowest concentration tested;if hitc >= 0.9 and ac50 < 10^logc_min, then flag.", "mc6_mthd": "ac50.lowconc", "mc6_mthd_id": 18}, {"desc": "Flag low efficacy hits if series has an active hit call (hitc >= 0.9) and efficacy values (e.g. top and maximum median response) less than 50 percent; intended for biochemical assays. If hitc >= 0.9 and coff >= 5, then flag when top < 50 or max_med < 50. If hitc >= 0.9 and coff < 5, then flag when top < log2(1.5) or max_med < log2(1.5).", "mc6_mthd": "efficacy.50", "mc6_mthd_id": 17}, {"desc": "Flag series where winning model is gain-loss (gnls) and the gain AC50 is less than the minimum tested concentration, and the loss AC50 is less than the mean tested concentration.", "mc6_mthd": "gnls.lowconc", "mc6_mthd_id": 15}, {"desc": "Flag series if 4 concentrations or less were tested; nconc <= 4.", "mc6_mthd": "low.nconc", "mc6_mthd_id": 14}, {"desc": "Flag series if the average number of replicates per concentration is less than 2; nrep < 2.", "mc6_mthd": "low.nrep", "mc6_mthd_id": 13}, {"desc": "Flag series if borderline activity is suspected based on modeled top parameter (top) relative to cutoff (coff); |top| <= 1.2(coff) or |top| >= 0.8(coff).", "mc6_mthd": "border", "mc6_mthd_id": 11}, {"desc": "Flag series as noisy if the quality of fit as calculated by the root mean square error (rmse) for the series is greater than the cutoff (coff); rmse > coff.", "mc6_mthd": "noise", "mc6_mthd_id": 10}, {"desc": "Flag series if modeled benchmark dose (BMD) is greater than AC50 (concentration at 50 percent maximal response). This is indicates high variability in baseline response in excess of more than half of the maximal response.", "mc6_mthd": "bmd.high", "mc6_mthd_id": 9}, {"desc": "Flag multi-point miss, where series is an inactive hit call (hitc < 0.9) with multiple median responses observed above baseline.", "mc6_mthd": "multipoint.neg", "mc6_mthd_id": 8}, {"desc": "Flag single-point hit that''s not at the highest conc tested, where series is an active hit call (hitc >= 0.9) with the median response observed above baseline occurring only at one concentration and not the highest concentration tested.", "mc6_mthd": "singlept.hit.mid", "mc6_mthd_id": 7}, {"desc": "Flag single-point hit that''s only at the highest conc tested, where series is an active hit call (hitc >= 0.9) with the median response observed above baseline occurring only at the highest tested concentration tested. ", "mc6_mthd": "singlept.hit.high", "mc6_mthd_id": 6}, {"desc": "Flag series if model directionality is questionable, i.e. if the winning model direction was opposite, more responses (resp) would have exceeded the cutoff (coff). If loss was winning directionality (top < 0), flag if count(resp < -1*coff) < 2*count(resp > coff). If gain was winning directionality (top > 0), flag if count(resp > coff) < 2*count(resp < -1*coff).", "mc6_mthd": "modl.directionality.fail", "mc6_mthd_id": 5}]','[{"desc": "Use raw value (rval) as is. This may be necessary for additional endpoint-specific adjustments, or where no additional sc1 methods are needed.", "sc1_mthd": "none", "sc1_mthd_id": 14}, {"desc": "Transform the response values to log-scale (base 2).", "sc1_mthd": "resp.log2", "sc1_mthd_id": 13}]','[{"desc": "Add a cutoff value of 5 multiplied the baseline median absolute deviation (bmad). By default, bmad is calculated using test compound wells (wllt = t) for the endpoint.", "sc2_mthd": "bmad5", "sc2_mthd_id": 5}]','2025-03-12','prod_internal_invitrodb_v4_2'),
	 (3032,'CCTE_GLTED_hIYD','Data from the assay component CCTE_GLTED_hIYD was analyzed at the assay endpoint CCTE_GLTED_hIYD in the positive analysis fitting direction relative to DMSO as the negative control and baseline of activity. Using a type of enzyme reporter, loss-of-signal activity can be used to understand iodotyrosine deiodinase activity. To generalize the intended target to other relatable targets, this assay endpoint is annotated to the ''dehalogenase'' intended target family, where the subfamily is ''iodotyrosine deiodinase''.','enzymatic activity','percent_activity',0,'3-Nitro-L-tyrosine (0.05 M NaOH for model inhibitor (MNT))','loss','protein','enzyme','dehalogenase','iodotyrosine deiodinase',0,2818,'CCTE_GLTED_hIYD','CCTE_GLTED_hIYD is the assay component measured from the CCTE_GLTED_hIYD assay. It measures substrate involved in regulation of catalytic activity using spectrophotometry. The assay measures the deiodination activity of human IYD on the substrate monoiodotyrosine (MIT).  After 3h incubation of substrate, enzyme, and test chemical, the components are applied to a 96-well Dowex column. Free iodide is not retained by the column and is separated from interfering assay components. The free iodide is measured by the Sandell-Kolthoff reaction in which the rate of reduction of cerium (Ce+4 to Ce+3) by arsenic (As+3 to As+5) is increased by the presence of iodide. This is observed as the loss of yellow color in the reaction and the quantified by the change in absorbance at 420 nm. The change in reaction rate is proportional to the amount of iodide present.','The iodide recycling enzyme, iodotyrosine deiodinase (IYD), is one conserved putative molecular target that plays an essential role in maintaining adequate levels of free iodide in the thyroid gland for hormone synthesis.','single','enzyme reporter','enzyme activity','regulation of catalytic activity','Absorbance ','Colorimetric','Spectrophotometry','substrate','Monoiodotyrosine (MIT)','protein','enzyme',866,'CCTE_GLTED_hIYD','CCTE_GLTED_hIYD is a cell-free, single-readout assay that uses human iodotyrosine deiodinase (hIYD) enzyme produced with baculovirus-insect cell system. The assay is based on iodide release measured by the Sandell-Kolthoff method and is run in 96-well plate format with assay plates run in triplicate (n=3) with measurements taken at 3 hours after chemical dosing. Platewise-normalization was used based on positive control (3-Nitro-L-tyrosine, MNT) and negative/solvent controls (DMSO, NaOH).',3.0,9606,'human',9606,'Homo sapiens','human','Eukaryota; Metazoa; Chordata; Craniata; Vertebrata; Euteleostomi; Mammalia; Eutheria; Euarchontoglires; Primates; Haplorrhini; Catarrhini; Hominidae; Homo','NA','cell-free','baculovirus-insect cells','SF-21','NA','microplate: 96-well plate','biochemical','protein single format','single','DMSO',1.65,24,'CCTE_GLTED','CCTE Great Lakes Toxicology and Ecology Division','The EPA CCTE Great Lakes Toxicology and Ecology Division focuses on ecotoxicology and stressors of water resources, including devleopment and implementation of in vitro and in vivo assays.','66df2da7e4b0a7c65d2ed85e ','[{"gene_id": 24338, "gene_name": "iodotyrosine deiodinase", "description": null, "gene_symbol": "IYD", "organism_id": 1, "track_status": null, "entrez_gene_id": 389434, "official_symbol": "IYD", "official_full_name": "iodotyrosine deiodinase", "uniprot_accession_number": null}]','[{"name": "Thyroid Bioactivity", "description": "Assays related to the thyroid adverse outcome pathway network"}]','[{"doi": "10.1016/j.tiv.2020.105073", "url": "https://pubmed.ncbi.nlm.nih.gov/33352258/", "pmid": 33352258, "title": "In vitro screening for chemical inhibition of the iodide recycling enzyme, iodotyrosine deiodinase", "author": "Olker JH, Korte JJ, Denny JS, Haselman JT, Hartig PC, Cardon MC, Hornung MW, Degitz SJ", "citation": "Olker JH, Korte JJ, Denny JS, Haselman JT, Hartig PC, Cardon MC, Hornung MW, Degitz SJ. In vitro screening for chemical inhibition of the iodide recycling enzyme, iodotyrosine deiodinase. Toxicol In Vitro. 2021 Mar;71:105073. doi: 10.1016/j.tiv.2020.105073. Epub 2020 Dec 29. PMID: 33352258; PMCID: PMC8130633.", "other_id": "0", "citation_id": 239, "other_source": ""}, {"doi": "10.1016/j.tiv.2023.105762.", "url": "https://pubmed.ncbi.nlm.nih.gov/38072180/", "pmid": 38072180, "title": "In vitro screening of per- and polyfluorinated substances (PFAS) for interference with seven thyroid hormone system targets across nine assays.", "author": "Degitz, S. J., Olker, J. H., Denny, J. S., Degoey, P. P., Hartig, P. C., Cardon, M. C., Eytcheson, S. A., Haselman, J. T., Mayasich, S. A., & Hornung, M. W.", "citation": "Degitz, S. J., Olker, J. H., Denny, J. S., Degoey, P. P., Hartig, P. C., Cardon, M. C., Eytcheson, S. A., Haselman, J. T., Mayasich, S. A., & Hornung, M. W. (2024). In vitro screening of per- and polyfluorinated substances (PFAS) for interference with seven thyroid hormone system targets across nine assays. Toxicology in vitro : an international journal published in association with BIBRA, 95, 105762. https://doi.org/10.1016/j.tiv.2023.105762", "other_id": "0", "citation_id": 305, "other_source": null}]',NULL,'[{"desc": "Use corrected response value (cval) as is; cval = cval. No additional mc2 methods needed for component-specific corrections.", "mc2_mthd": "none", "exec_ordr": 1, "mc2_mthd_id": 1}]','[{"desc": "Set the corrected response value (cval) as the normalized response value (resp); cval = resp. No additional mc3 methods needed for endpoint-specific normalization.", "mc3_mthd": "none", "mc3_mthd_id": 1}]','[{"desc": "Calculate the baseline median absolute value (bmad) as the median absolute deviation of normalized response values (resp) for neutral control wells (wllt = n). Calculate one standard deviation of the normalized response for neutral control wells (wllt = n); onesd = sqrt(sum((resp - mean resp)^2)/sample size - 1). Onesd is used to establish BMR and therefore required for tcplfit2 processing.", "mc4_mthd": "bmad.aeid.lowconc.nwells", "mc4_mthd_id": 2}]','[{"desc": "Add a cutoff value of 20. Typically for percent of control data.", "mc5_mthd": "pc20", "mc5_mthd_id": 2}, {"desc": "Multiply winning model hitcall (hitc) by -1\r for models fit in the negative analysis direction. Typically used for\r endpoints where only positive responses are biologically relevant.", "mc5_mthd": "ow_bidirectional_gain", "mc5_mthd_id": 28}]','[{"desc": "Flag series where no median response values are greater than baseline as defined by 3 times the baseline median absolute deviation (bmad); nmed_gtbl_pos and nmed_gtbl_neg both = 0, where nmed_gtbl_pos/_neg is the number of medians greater than 3*bmad/less than -3*bmad.", "mc6_mthd": "no.med.gt.3bmad", "mc6_mthd_id": 20}, {"desc": "Flag series with an active hit call (hitc >= 0.9) if AC50 (concentration at 50 percent maximal response) is less than the lowest concentration tested;if hitc >= 0.9 and ac50 < 10^logc_min, then flag.", "mc6_mthd": "ac50.lowconc", "mc6_mthd_id": 18}, {"desc": "Flag low efficacy hits if series has an active hit call (hitc >= 0.9) and efficacy values (e.g. top and maximum median response) less than 50 percent; intended for biochemical assays. If hitc >= 0.9 and coff >= 5, then flag when top < 50 or max_med < 50. If hitc >= 0.9 and coff < 5, then flag when top < log2(1.5) or max_med < log2(1.5).", "mc6_mthd": "efficacy.50", "mc6_mthd_id": 17}, {"desc": "Flag series where winning model is gain-loss (gnls) and the gain AC50 is less than the minimum tested concentration, and the loss AC50 is less than the mean tested concentration.", "mc6_mthd": "gnls.lowconc", "mc6_mthd_id": 15}, {"desc": "Flag series if 4 concentrations or less were tested; nconc <= 4.", "mc6_mthd": "low.nconc", "mc6_mthd_id": 14}, {"desc": "Flag series if the average number of replicates per concentration is less than 2; nrep < 2.", "mc6_mthd": "low.nrep", "mc6_mthd_id": 13}, {"desc": "Flag series if borderline activity is suspected based on modeled top parameter (top) relative to cutoff (coff); |top| <= 1.2(coff) or |top| >= 0.8(coff).", "mc6_mthd": "border", "mc6_mthd_id": 11}, {"desc": "Flag series as noisy if the quality of fit as calculated by the root mean square error (rmse) for the series is greater than the cutoff (coff); rmse > coff.", "mc6_mthd": "noise", "mc6_mthd_id": 10}, {"desc": "Flag series if modeled benchmark dose (BMD) is greater than AC50 (concentration at 50 percent maximal response). This is indicates high variability in baseline response in excess of more than half of the maximal response.", "mc6_mthd": "bmd.high", "mc6_mthd_id": 9}, {"desc": "Flag multi-point miss, where series is an inactive hit call (hitc < 0.9) with multiple median responses observed above baseline.", "mc6_mthd": "multipoint.neg", "mc6_mthd_id": 8}, {"desc": "Flag single-point hit that''s not at the highest conc tested, where series is an active hit call (hitc >= 0.9) with the median response observed above baseline occurring only at one concentration and not the highest concentration tested.", "mc6_mthd": "singlept.hit.mid", "mc6_mthd_id": 7}, {"desc": "Flag single-point hit that''s only at the highest conc tested, where series is an active hit call (hitc >= 0.9) with the median response observed above baseline occurring only at the highest tested concentration tested. ", "mc6_mthd": "singlept.hit.high", "mc6_mthd_id": 6}, {"desc": "Flag series if model directionality is questionable, i.e. if the winning model direction was opposite, more responses (resp) would have exceeded the cutoff (coff). If loss was winning directionality (top < 0), flag if count(resp < -1*coff) < 2*count(resp > coff). If gain was winning directionality (top > 0), flag if count(resp > coff) < 2*count(resp < -1*coff).", "mc6_mthd": "modl.directionality.fail", "mc6_mthd_id": 5}]','[{"desc": "Use raw value (rval) as is. This may be necessary for additional endpoint-specific adjustments, or where no additional sc1 methods are needed.", "sc1_mthd": "none", "sc1_mthd_id": 14}]','[{"desc": "Where responses only in the positive direction are biologically relevant, overwrite the max_med and max_tmp values, which were calculated using absolute value, to a calculation using a true maximum for uni-directional data.", "sc2_mthd": "ow_bidirectional_gain", "sc2_mthd_id": 25}, {"desc": "Overwrite the default baseline median absolute value (bmad) with a bmad calculated using neutral control wells (wllt = n).", "sc2_mthd": "ow_bmad_nwells", "sc2_mthd_id": 20}, {"desc": "Add a cutoff value of 20. Typically for percent of control data.", "sc2_mthd": "pc20", "sc2_mthd_id": 2}]','2025-03-12','prod_internal_invitrodb_v4_2'),
	 (2387,'UPITT_HCI_U2OS_AR_TIF2_Nucleoli_Agonist','Data from the assay component UPITT_HCI_U2OS_AR_TIF2_Nucleoli_Agonist was analyzed into 1 assay endpoint. This assay endpoint, UPITT_HCI_U2OS_AR_TIF2_Nucleoli_Agonist, was analyzed in the positive analysis fitting direction relative to DMSO as the baseline of activity. Using a type of binding reporter, measures of receptor for gain-of-signal activity can be used to understand the binding at the pathway-level as it relates to the gene AR.','binding','percent_activity',0,'dihydroxytestosterone (DHT)','gain','pathway','pathway-specified','nuclear receptor','steroidal',0,2394,'UPITT_HCI_U2OS_AR_TIF2_Nucleoli_Agonist','UPITT_HCI_U2OS_AR_TIF2_Nucleoli_Agonist is one of four assay components measured from the UPITT_AR_TIF2_PPIB assay. It is designed to make measurements of red fluorescence localized in the nucleolar region of the cell nucleus as detected with high-content fluorescent imaging.','Increased red fluorescence in nucleolar region of the cell nucleus is consistent with agonism of human androgen receptor activity [GeneSymbol: AR | GeneID: 367 |','single','binding reporter','protein-protein binding','receptor binding','Fluorescence','Optical microscopy: Fluorescence microscopy','HCS Fluorescent Imaging','NA','NA','protein','receptor binding',681,'UPITT_AR_TIF2_PPIB','UPITT_AR_TIF2_PPIB is a cell-based, high-content imaging assay that uses U2OS, a human osteosarcoma cell line, expressing a human androgen receptor fused to red fluorescent protein and the coactivator TIF2 fused to green fluorescent protein. ',3.0,9606,'human',9606,'Homo sapiens','human','Eukaryota; Metazoa; Chordata; Craniata; Vertebrata; Euteleostomi; Mammalia; Eutheria; Euarchontoglires; Primates; Haplorrhini; Catarrhini; Hominidae; Homo','bone','cell line','NA','U2OS',NULL,'microplate: 384-well plate','cell-based','protein complex format','image-based','DMSO',0.5,25,'UPITT','University of Pittsburgh Johnston Lab','The Johnston Lab at the University of Pittsburgh ran androgen receptor nuclear translocation assays under a Material Transfer Agreement (MTA) for the ToxCast Phase 1, Phase 2, and E1K chemicals. ',NULL,'[{"gene_id": 27, "gene_name": "androgen receptor", "description": null, "gene_symbol": "AR", "organism_id": 1, "track_status": "live", "entrez_gene_id": 367, "official_symbol": "AR", "official_full_name": "androgen receptor", "uniprot_accession_number": "P10275"}]','[{"name": "ToxCast AR Pathway Model", "description": "Androgen receptor assays used in ToxCast AR Pathway model. See 10.1016/j.yrtph.2020.104764 and 10.1021/acs.chemrestox.6b00347"}]','[{"doi": "10.1016/j.yrtph.2020.104764", "url": "https://pubmed.ncbi.nlm.nih.gov/32798611/", "pmid": 32798611, "title": "Selecting a minimal set of androgen receptor assays for screening chemicals", "author": "Judson R, Houck K, Paul Friedman K, Brown J, Browne P, Johnston PA, Close DA, Mansouri K, Kleinstreuer N", "citation": "Judson R, Houck K, Paul Friedman K, Brown J, Browne P, Johnston PA, Close DA, Mansouri K, Kleinstreuer N. Selecting a minimal set of androgen receptor assays for screening chemicals. Regul Toxicol Pharmacol. 2020 Nov;117:104764. doi: 10.1016/j.yrtph.2020.104764. Epub 2020 Aug 14. PMID: 32798611; PMCID: PMC8356084.", "other_id": "0", "citation_id": 283, "other_source": ""}]',NULL,'[{"desc": "Use corrected response value (cval) as is; cval = cval. No additional mc2 methods needed for component-specific corrections.", "mc2_mthd": "none", "exec_ordr": 1, "mc2_mthd_id": 1}]','[{"desc": "Calculate the positive control value (pval) as the plate-wise median, by assay plate ID (apid), of the corrected values (cval) for single-concentration gain-of-signal positive control wells (wllt = p).", "mc3_mthd": "pval.apid.pwlls.med", "mc3_mthd_id": 13}, {"desc": "Calculate the baseline value (bval) as the plate-wise median, by assay plate ID (apid), of the corrected values (cval) for neutral control wells (wllt = n).", "mc3_mthd": "bval.apid.nwlls.med", "mc3_mthd_id": 11}, {"desc": "Calculate the normalized response (resp) as a percent of control, i.e. the ratio of the difference between the corrected (cval) and baseline (bval) values divided the difference between the positive control (pval) and baseline (bval) values multiplied by 100; resp = (cval-bval)/(pval-bval)*100.", "mc3_mthd": "resp.pc", "mc3_mthd_id": 5}]','[{"desc": "Calculate the baseline median absolute value (bmad) as the median absolute deviation of normalized response values (rep) for test compound wells (wllt = t) with concentration index (cndx) equal to 1 or 2. Calculate one standard deviation of the normalized response for test compound wells (wllt = t) with a concentration index (cndx) of 1 or 2; onesd = sqrt(sum((resp - mean resp)^2)/sample size - 1). Onesd is used to establish BMR and therefore required for tcplfit2 processing.", "mc4_mthd": "bmad.aeid.lowconc.twells", "mc4_mthd_id": 1}]','[{"desc": "Add a cutoff value of 3 multiplied by the baseline median absolute deviation (bmad) as defined at Level 4.", "mc5_mthd": "bmad3", "mc5_mthd_id": 1}, {"desc": "Add a cutoff value of 20. Typically for percent of control data.", "mc5_mthd": "pc20", "mc5_mthd_id": 2}, {"desc": "Multiply winning model hitcall (hitc) by -1\r for models fit in the negative analysis direction. Typically used for\r endpoints where only positive responses are biologically relevant.", "mc5_mthd": "ow_bidirectional_gain", "mc5_mthd_id": 28}]','[{"desc": "Flag series where no median response values are greater than baseline as defined by 3 times the baseline median absolute deviation (bmad); nmed_gtbl_pos and nmed_gtbl_neg both = 0, where nmed_gtbl_pos/_neg is the number of medians greater than 3*bmad/less than -3*bmad.", "mc6_mthd": "no.med.gt.3bmad", "mc6_mthd_id": 20}, {"desc": "Flag series with an active hit call (hitc >= 0.9) if AC50 (concentration at 50 percent maximal response) is less than the lowest concentration tested;if hitc >= 0.9 and ac50 < 10^logc_min, then flag.", "mc6_mthd": "ac50.lowconc", "mc6_mthd_id": 18}, {"desc": "Flag low efficacy hits if series has an active hit call (hitc >= 0.9) and efficacy values (e.g. top and maximum median response) less than 50 percent; intended for biochemical assays. If hitc >= 0.9 and coff >= 5, then flag when top < 50 or max_med < 50. If hitc >= 0.9 and coff < 5, then flag when top < log2(1.5) or max_med < log2(1.5).", "mc6_mthd": "efficacy.50", "mc6_mthd_id": 17}, {"desc": "Flag series where winning model is gain-loss (gnls) and the gain AC50 is less than the minimum tested concentration, and the loss AC50 is less than the mean tested concentration.", "mc6_mthd": "gnls.lowconc", "mc6_mthd_id": 15}, {"desc": "Flag series if 4 concentrations or less were tested; nconc <= 4.", "mc6_mthd": "low.nconc", "mc6_mthd_id": 14}, {"desc": "Flag series if the average number of replicates per concentration is less than 2; nrep < 2.", "mc6_mthd": "low.nrep", "mc6_mthd_id": 13}, {"desc": "Flag series if borderline activity is suspected based on modeled top parameter (top) relative to cutoff (coff); |top| <= 1.2(coff) or |top| >= 0.8(coff).", "mc6_mthd": "border", "mc6_mthd_id": 11}, {"desc": "Flag series as noisy if the quality of fit as calculated by the root mean square error (rmse) for the series is greater than the cutoff (coff); rmse > coff.", "mc6_mthd": "noise", "mc6_mthd_id": 10}, {"desc": "Flag series if modeled benchmark dose (BMD) is greater than AC50 (concentration at 50 percent maximal response). This is indicates high variability in baseline response in excess of more than half of the maximal response.", "mc6_mthd": "bmd.high", "mc6_mthd_id": 9}, {"desc": "Flag multi-point miss, where series is an inactive hit call (hitc < 0.9) with multiple median responses observed above baseline.", "mc6_mthd": "multipoint.neg", "mc6_mthd_id": 8}, {"desc": "Flag single-point hit that''s not at the highest conc tested, where series is an active hit call (hitc >= 0.9) with the median response observed above baseline occurring only at one concentration and not the highest concentration tested.", "mc6_mthd": "singlept.hit.mid", "mc6_mthd_id": 7}, {"desc": "Flag single-point hit that''s only at the highest conc tested, where series is an active hit call (hitc >= 0.9) with the median response observed above baseline occurring only at the highest tested concentration tested. ", "mc6_mthd": "singlept.hit.high", "mc6_mthd_id": 6}, {"desc": "Flag series if model directionality is questionable, i.e. if the winning model direction was opposite, more responses (resp) would have exceeded the cutoff (coff). If loss was winning directionality (top < 0), flag if count(resp < -1*coff) < 2*count(resp > coff). If gain was winning directionality (top > 0), flag if count(resp > coff) < 2*count(resp < -1*coff).", "mc6_mthd": "modl.directionality.fail", "mc6_mthd_id": 5}]','[{"desc": null, "sc1_mthd": null, "sc1_mthd_id": null}]','[{"desc": null, "sc2_mthd": null, "sc2_mthd_id": null}]','2025-03-12','prod_internal_invitrodb_v4_2');

