-- invitro.mv_bioactivity_model
INSERT INTO invitro.mv_bioactivity_model (id,dtxsid,model,receptor,agonist,antagonist,binding,help) VALUES
	 (1197521,'DTXSID7020182','COMPARA (Consensus)','Androgen','0','1','1','CoMPARA is a larger scale collaboration between 35 international groups, using QSAR models to predict androgen receptor activity using a common training set of 1746 compounds provided by U.S. EPA. A key result is a consensus model of AR agonist and antagonist activity that is run against the DSSTox chemical library. These results are intended to be used in prioritization for compounds for follow-up testing. More details about the project are available on <a href=''https://www.researchgate.net/publication/316606155_CoMPARA_Collaborative_Modeling_Project_for_Androgen_Receptor_Activity''target=''_blank''>ResearchGate</a>.'),
	 (1280016,'DTXSID7020182','ToxCast Pathway Model (AUC)','Estrogen','0.45','0','-','The publications associated with the ToxCast Pathway Models are: 1) ESTROGEN: As described in Browne, et al (2015) DOI: <a href=''https://doi.org/10.1021/acs.est.5b02641''target=''_blank''>10.1021/acs.est.5b02641</a> and presented to December 2014 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2014-0614''target=''_blank''> EPA-HQ-OPP-2014-0614</a>. 2) ANDROGEN: As described in Kleinstreuer et al (2017) <a href=''https://pubs.acs.org/doi/10.1021/acs.chemrestox.6b00347''target=''_blank''>10.1021/acs.chemrestox.6b00347</a> and presented to November 2017 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2017-0214''target=''_blank''> EPA-HQ-OPP-2017-0214</a>.'),
	 (1296379,'DTXSID7020182','CERAPP Potency Level (From Literature)','Estrogen','Weak','Strong','Weak','As described in Mansouri, et al (2016) DOI: <a href=''https://doi.org/10.1289/ehp.1510267''target=''_blank''>10.1289/ehp.1510267</a>.'),
	 (1307716,'DTXSID7020182','CERAPP Potency Level (Consensus)','Estrogen','1','1','1','As described in Mansouri, et al (2016) DOI: <a href=''https://doi.org/10.1289/ehp.1510267''target=''_blank''>10.1289/ehp.1510267</a>.'),
	 (1316572,'DTXSID7020182','ToxCast Pathway Model (AUC)','Androgen','0','0.345','-','The publications associated with the ToxCast Pathway Models are: 1) ESTROGEN: As described in Browne, et al (2015) DOI: <a href=''https://doi.org/10.1021/acs.est.5b02641''target=''_blank''>10.1021/acs.est.5b02641</a> and presented to December 2014 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2014-0614''target=''_blank''> EPA-HQ-OPP-2014-0614</a>. 2) ANDROGEN: As described in Kleinstreuer et al (2017) <a href=''https://pubs.acs.org/doi/10.1021/acs.chemrestox.6b00347''target=''_blank''>10.1021/acs.chemrestox.6b00347</a> and presented to November 2017 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2017-0214''target=''_blank''> EPA-HQ-OPP-2017-0214</a>.'),
	 (1191002,'DTXSID9020112','ToxCast Pathway Model (AUC)','Estrogen','0','0','-','The publications associated with the ToxCast Pathway Models are: 1) ESTROGEN: As described in Browne, et al (2015) DOI: <a href=''https://doi.org/10.1021/acs.est.5b02641''target=''_blank''>10.1021/acs.est.5b02641</a> and presented to December 2014 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2014-0614''target=''_blank''> EPA-HQ-OPP-2014-0614</a>. 2) ANDROGEN: As described in Kleinstreuer et al (2017) <a href=''https://pubs.acs.org/doi/10.1021/acs.chemrestox.6b00347''target=''_blank''>10.1021/acs.chemrestox.6b00347</a> and presented to November 2017 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2017-0214''target=''_blank''> EPA-HQ-OPP-2017-0214</a>.'),
	 (1213309,'DTXSID9020112','CERAPP Potency Level (Consensus)','Estrogen','0','0','0','As described in Mansouri, et al (2016) DOI: <a href=''https://doi.org/10.1289/ehp.1510267''target=''_blank''>10.1289/ehp.1510267</a>.'),
	 (1245523,'DTXSID9020112','CERAPP Potency Level (From Literature)','Estrogen','Inactive','Inactive','Inactive','As described in Mansouri, et al (2016) DOI: <a href=''https://doi.org/10.1289/ehp.1510267''target=''_blank''>10.1289/ehp.1510267</a>.'),
	 (1247730,'DTXSID9020112','COMPARA (Consensus)','Androgen','0','0','0','CoMPARA is a larger scale collaboration between 35 international groups, using QSAR models to predict androgen receptor activity using a common training set of 1746 compounds provided by U.S. EPA. A key result is a consensus model of AR agonist and antagonist activity that is run against the DSSTox chemical library. These results are intended to be used in prioritization for compounds for follow-up testing. More details about the project are available on <a href=''https://www.researchgate.net/publication/316606155_ CoMPARA_Collaborative_Modeling_Project_for_Androgen_Receptor_Activity''target=''_blank''>ResearchGate</a>.'),
	 (1325963,'DTXSID9020112','ToxCast Pathway Model (AUC)','Androgen','0','0','-','The publications associated with the ToxCast Pathway Models are: 1) ESTROGEN: As described in Browne, et al (2015) DOI: <a href=''https://doi.org/10.1021/acs.est.5b02641''target=''_blank''>10.1021/acs.est.5b02641</a> and presented to December 2014 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2014-0614''target=''_blank''> EPA-HQ-OPP-2014-0614</a>. 2) ANDROGEN: As described in Kleinstreuer et al (2017) <a href=''https://pubs.acs.org/doi/10.1021/acs.chemrestox.6b00347''target=''_blank''>10.1021/acs.chemrestox.6b00347</a> and presented to November 2017 FIFRA SAP under <a href=''https://www.regulations.gov/docket?D=EPA-HQ-OPP-2017-0214''target=''_blank''> EPA-HQ-OPP-2017-0214</a>.');

