INSERT INTO invitro.search_assay (aeid,search_name,search_value,search_value_desc,modified_value,data_version,export_date) VALUES
	 (111,'assay','ATG_TCF_b_cat_CIS','Data from the assay component ATG_TCF_b_cat_CIS was analyzed into 1 assay endpoint. This assay endpoint, ATG_TCF_b_cat_CIS, was analyzed with bidirectional fitting relative to DMSO as the negative control and baseline of activity. Using a type of inducible reporter, measures of mRNA for gain or loss-of-signal activity can be used to understand the reporter gene at the transcription factor-level as they relate to the gene TCF7 and TCF7L2 and LEF1 and TCF7L1. Furthermore, this assay endpoint can be referred to as a primary readout, because this assay has produced multiple assay endpoints where this one serves a reporter gene function. To generalize the intended target to other relatable targets, this assay endpoint is annotated to the dna binding intended target family, where the subfamily is HMG box protein.','ATG_TCF_B_CAT_CIS','prod_internal_invitrodb_v4_2','2025-03-12'),
	 (3032,'assay','CCTE_GLTED_hIYD','Data from the assay component CCTE_GLTED_hIYD was analyzed at the assay endpoint CCTE_GLTED_hIYD in the positive analysis fitting direction relative to DMSO as the negative control and baseline of activity. Using a type of enzyme reporter, loss-of-signal activity can be used to understand iodotyrosine deiodinase activity. To generalize the intended target to other relatable targets, this assay endpoint is annotated to the ''dehalogenase'' intended target family, where the subfamily is ''iodotyrosine deiodinase''.','CCTE_GLTED_HIYD','prod_internal_invitrodb_v4_2','2025-03-12'),
	 (3032,'gene','IYD','iodotyrosine deiodinase','IYD IODOTYROSINE DEIODINASE','prod_internal_invitrodb_v4_2','2025-03-12'),
	 (111,'gene','TCF7','transcription factor 7 (T-cell specific, HMG-box)','TCF7 TRANSCRIPTION FACTOR 7 (T-CELL SPECIFIC, HMG-BOX)','prod_internal_invitrodb_v4_2','2025-03-12'),
	 (111,'gene','LEF1','lymphoid enhancer-binding factor 1','LEF1 LYMPHOID ENHANCER-BINDING FACTOR 1','prod_internal_invitrodb_v4_2','2025-03-12'),
	 (111,'gene','TCF7L1','transcription factor 7-like 1 (T-cell specific, HMG-box)','TCF7L1 TRANSCRIPTION FACTOR 7-LIKE 1 (T-CELL SPECIFIC, HMG-BOX)','prod_internal_invitrodb_v4_2','2025-03-12'),
	 (111,'gene','TCF7L2','transcription factor 7-like 2 (T-cell specific, HMG-box)','TCF7L2 TRANSCRIPTION FACTOR 7-LIKE 2 (T-CELL SPECIFIC, HMG-BOX)','prod_internal_invitrodb_v4_2','2025-03-12');

